// Alertmanager sends { alerts: [...] }
const payload = $input.item.json;
const alerts = payload.alerts || [payload];
const now = Date.now();
const SUPPRESS_WINDOW_MS = 30 * 60 * 1000; // 30 minutes

// Get or init staticData for dedup
const staticData = $getWorkflowStaticData('global');
if (!staticData.seen) staticData.seen = {};

// Clean up expired entries
for (const [fp, ts] of Object.entries(staticData.seen)) {
  if (now - ts > SUPPRESS_WINDOW_MS) delete staticData.seen[fp];
}

const passThrough = [];

for (const alert of alerts) {
  const fingerprint = alert.fingerprint || `${alert.labels?.alertname || 'unknown'}-${alert.labels?.instance || ''}`;
  const status = alert.status || 'firing';

  // Always pass resolved alerts
  if (status === 'resolved') {
    delete staticData.seen[fingerprint];
    passThrough.push({ ...alert, _fingerprint: fingerprint, _dedupStatus: 'resolved-passthrough' });
    continue;
  }

  // Check dedup window for firing alerts
  if (staticData.seen[fingerprint]) {
    continue; // Suppressed
  }

  staticData.seen[fingerprint] = now;
  passThrough.push({ ...alert, _fingerprint: fingerprint, _dedupStatus: 'new' });
}

if (passThrough.length === 0) {
  return []; // All suppressed — stop workflow
}

return passThrough.map(a => ({ json: a }));

const alert = $('Dedup Alerts (30min)').item.json;
const errorSummary = $('Enrich from Error Summary').item.json;

const alertname = alert.labels?.alertname || 'Unknown Alert';
const status = alert.status || 'firing';
const severity = alert.labels?.severity || 'warning';
const instance = alert.labels?.instance || 'unknown';
const description = alert.annotations?.description || alert.annotations?.summary || alertname;
const startsAt = alert.startsAt || '';
const endsAt = alert.endsAt || '';
const dedupStatus = alert._dedupStatus;

// Severity classification
let level;
if (status === 'resolved') {
  level = 'resolved';
} else if (severity === 'critical' || alertname.toLowerCase().includes('down') || alertname.toLowerCase().includes('critical')) {
  level = 'critical';
} else if (severity === 'warning') {
  level = 'warning';
} else {
  level = 'info';
}

const colors = { critical: 15548997, warning: 16776960, info: 3447003, resolved: 3066993 };
const icons = { critical: '🔴', warning: '🟡', info: '🔵', resolved: '🟢' };

// Recent error context
const recentErrors = errorSummary.errors || errorSummary.summary || [];
const totalRecentErrors = errorSummary.totalErrors || errorSummary.total || 0;
let errorContext = `${totalRecentErrors} errors in the last hour`;
if (recentErrors.length > 0) {
  const topErrors = recentErrors.slice(0, 3).map(e => `• ${e.message || e.error || 'Unknown'} (×${e.count || 1})`).join('\n');
  errorContext += '\n' + topErrors;
}

const embed = {
  title: `${icons[level]} ${alertname}`,
  description: description,
  color: colors[level],
  timestamp: new Date().toISOString(),
  fields: [
    { name: 'Status', value: status.toUpperCase(), inline: true },
    { name: 'Severity', value: level.toUpperCase(), inline: true },
    { name: 'Instance', value: instance, inline: true },
  ],
};

if (status !== 'resolved') {
  embed.fields.push({ name: 'Recent Errors (1h)', value: errorContext, inline: false });
}

if (startsAt) {
  embed.fields.push({ name: 'Started', value: new Date(startsAt).toLocaleString(), inline: true });
}

if (status === 'resolved' && endsAt) {
  embed.fields.push({ name: 'Resolved', value: new Date(endsAt).toLocaleString(), inline: true });
}

embed.footer = { text: `Fingerprint: ${alert._fingerprint} | Dedup: ${dedupStatus}` };

return [{ json: { embed, level } }];
